import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const ACTIVITY_LEVELS = [
  { label: "Sedentary", desc: "Little or no exercise", factor: 1.2 },
  { label: "Lightly Active", desc: "1-3 days/week", factor: 1.375 },
  { label: "Moderately Active", desc: "3-5 days/week", factor: 1.55 },
  { label: "Very Active", desc: "6-7 days/week", factor: 1.725 },
  { label: "Extra Active", desc: "2 x  daily / physical job", factor: 1.9 },
];

const FAQS = [
  { q: "How are daily calorie needs calculated?", a: "This calculator uses the Mifflin-St Jeor equation to calculate Basal Metabolic Rate (BMR), then multiplies by an activity factor to get Total Daily Energy Expenditure (TDEE) - your estimated daily calorie needs." },
  { q: "How many calories should I eat to lose weight?", a: "A 500 calorie/day deficit leads to approximately 1 pound of weight loss per week (3,500 calories - 1 lb). Eating 1,000 below TDEE = ~2 lbs/week. Most experts recommend no more than 1-2 lbs/week for sustainable loss." },
  { q: "What is BMR vs. TDEE?", a: "BMR (Basal Metabolic Rate) is the calories your body burns at complete rest. TDEE (Total Daily Energy Expenditure) is BMR multiplied by your activity level - the actual calories you burn per day accounting for movement." },
  { q: "Are these calorie estimates accurate?", a: "All BMR formulas are estimates with - variation. Individual metabolism varies based on genetics, hormones, muscle mass, and health conditions. Use this as a starting point and adjust based on real-world results." },
  { q: "What happens if I eat too few calories?", a: "Eating significantly below your BMR triggers metabolic adaptation - your body reduces energy output to conserve fat. This causes weight loss to stall, muscle loss, fatigue, and hormonal disruption. A reasonable deficit of 300-750 calories below TDEE avoids these effects." },
  { q: "How many calories are in a pound of fat?", a: "Approximately 3,500 calories equal one pound of body fat. Creating a 500 calorie/day deficit = 3,500 calories/week = ~1 lb of fat lost per week. This rule is a useful approximation, though actual results vary based on metabolism and adaptation." },
  { q: "Should I eat back calories I burn from exercise?", a: "Partially. Exercise calorie burns are often overestimated by 30-50%. A common approach is to eat back 50% of exercise calories to avoid over-fueling. If you selected an active activity level when calculating your TDEE, your exercise calories are already partially accounted for." },
];

export default function CalorieCalculator() {
  const [gender, setGender] = useState<"male" | "female">("male");
  const [age, setAge] = useState(30);
  const [heightCm, setHeightCm] = useState(175);
  const [weightKg, setWeightKg] = useState(75);
  const [activityIdx, setActivityIdx] = useState(1);

  const bmr = gender === "male"
    ? 10 * weightKg + 6.25 * heightCm - 5 * age + 5
    : 10 * weightKg + 6.25 * heightCm - 5 * age - 161;
  const tdee = Math.round(bmr * ACTIVITY_LEVELS[activityIdx].factor);
  const deficit500 = tdee - 500;
  const surplus300 = tdee + 300;

  return (
    <>
      <SEOHead
        title="Free Calorie Calculator Online - Find Your Daily Calorie Needs Instantly | CalcHive"
        description="Free online calorie calculator. Find your daily calorie needs and TDEE based on age, gender, height, weight and activity level. 100% free, instant results, no account needed."
        canonical="/calorie-calculator"
        keywords="free calorie calculator, TDEE calculator free online, daily calorie needs calculator free, free calorie intake calculator, calorie calculator no signup free"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Calorie Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free calorie calculator to estimate your daily calorie needs and TDEE from your personal details and activity level. This TDEE calculator free online also works as a daily calorie needs calculator free, free calorie intake calculator, and calorie calculator no signup free tool.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="flex gap-2 mb-6">
            {(["male", "female"] as const).map(g => (
              <button key={g} onClick={() => setGender(g)} className={`px-4 py-1.5 rounded-full text-sm font-semibold border capitalize transition-all ${gender === g ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>{g}</button>
            ))}
          </div>
          <div className="space-y-6 mb-6">
            <SliderInput id="age-cal" label="Age" value={age} min={1} max={120} step={0.1} onChange={setAge} format={v => `${v} years`} testId="input-age" />
            <SliderInput id="height-cal" label="Height" value={heightCm} min={91.44} max={243.84} step={0.1} onChange={setHeightCm} format={v => `${v} cm`} testId="input-height" />
            <SliderInput id="weight-cal" label="Weight" value={weightKg} min={30} max={635} step={0.1} onChange={setWeightKg} format={v => `${v} kg`} testId="input-weight" />
          </div>
          <div className="mb-8">
            <p className="text-sm font-semibold text-foreground mb-2">Activity Level</p>
            <div className="space-y-2">
              {ACTIVITY_LEVELS.map((a, i) => (
                <label key={a.label} className={`flex items-center gap-3 p-3 rounded-xl border cursor-pointer transition-all ${activityIdx === i ? "bg-accent border-primary/40" : "border-border"}`}>
                  <input type="radio" checked={activityIdx === i} onChange={() => setActivityIdx(i)} className="accent-primary" />
                  <span>
                    <span className="text-sm font-semibold text-foreground">{a.label}</span>
                    <span className="text-xs text-muted-foreground ml-2">{a.desc}</span>
                  </span>
                </label>
              ))}
            </div>
          </div>
          <motion.div key={`${gender}-${age}-${heightCm}-${weightKg}-${activityIdx}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Maintenance Calories (TDEE)</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-tdee">{tdee.toLocaleString()}</p>
              <p className="text-white/70 text-sm mt-1">calories per day</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[{ label: "For Weight Loss", value: `${deficit500.toLocaleString()} cal` }, { label: "For Maintenance", value: `${tdee.toLocaleString()} cal` }, { label: "For Weight Gain", value: `${surplus300.toLocaleString()} cal` }].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <MedicalDisclaimer /><ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Daily Calorie Needs for Free</h2>
          <p className="text-muted-foreground leading-relaxed">This calculator uses a two-step process: first calculating your Basal Metabolic Rate (BMR) using the Mifflin-St Jeor equation, then multiplying by an activity factor to get your actual daily calorie needs (TDEE).</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-2">
            <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Step 1: Mifflin-St Jeor BMR</p>
            <p>Male: BMR = (10  x  kg) + (6.25  x  cm) - (5  x  age) + 5</p>
            <p>Female: BMR = (10  x  kg) + (6.25  x  cm) - (5  x  age) - 161</p>
            <p className="text-xs text-muted-foreground uppercase tracking-widest mt-3 mb-1">Step 2: Activity Multiplier</p>
            <p>TDEE = BMR  x  Activity Factor (1.2 to 1.9)</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">What is TDEE and How to Use It</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Goal", "Calorie Target", "Expected Result", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Aggressive weight loss", "TDEE - 750", "~1.5 lbs/week", "Risk of muscle loss; short-term only"],
                  ["Moderate weight loss", "TDEE - 500", "~1 lb/week", "Sustainable, recommended approach"],
                  ["Slow weight loss", "TDEE - 250", "~0.5 lbs/week", "Best for preserving muscle"],
                  ["Maintenance", "TDEE", "Weight stable", "Adjust - cal based on weekly trend"],
                  ["Lean bulk (muscle gain)", "TDEE + 200-300", "~0.25 lbs/week", "Minimizes fat gain alongside muscle"],
                  ["Moderate bulk", "TDEE + 400-600", "~0.5 lbs/week", "Faster muscle gain, more fat accumulation"],
                ].map(([goal, target, result, notes]) => (
                  <tr key={goal} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{goal}</td>
                    <td className="py-2.5 px-4 text-teal-600 dark:text-teal-400 font-medium">{target}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{result}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free TDEE and Calorie Tool for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Food", "Serving", "Calories", "Protein"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Chicken breast (grilled)", "100g", "165 cal", "31g"],
                  ["Brown rice (cooked)", "1 cup (195g)", "216 cal", "5g"],
                  ["Egg (large)", "1 egg", "72 cal", "6g"],
                  ["Greek yogurt (plain)", "1 cup", "130 cal", "22g"],
                  ["Salmon (baked)", "100g", "206 cal", "20g"],
                  ["Banana", "1 medium", "105 cal", "1.3g"],
                  ["Almonds", "1 oz (28g)", "164 cal", "6g"],
                  ["Whole milk", "1 cup (240ml)", "149 cal", "8g"],
                  ["Oats (dry)", "- cup (40g)", "150 cal", "5g"],
                ].map(([food, serving, cal, protein]) => (
                  <tr key={food} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{food}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{serving}</td>
                    <td className="py-2.5 px-4 text-teal-600 dark:text-teal-400 font-medium">{cal}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{protein}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/calorie-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


